  ('locality-814ced5a-moex-00107', 'locality-814ced5a', 'locality-814ced5a-moex-111-01c5eaab', 'sub-locality-814ced5a-03', NULL, 'single_choice', '下列指稱物品的「量詞」，何者較不適宜？', '["他寫了一「封」信給交往已久的好朋友", "在臺南億載金城看到一「門」西式大炮", "老師請人刻了一「方」圖章作為開戶用", "朋友在酒過三「席」之後逐漸說話含糊"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:35:28+00:00", "source_pdf_sha1": "e90a507a577f", "answer_pdf_sha1": "69eb6bd30069", "source_family": "moex-gov-tw", "moex": {"exam_code": "111190", "c": "506", "s": "0105", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "國文(包括公文格式用語)", "year": "111", "exam_name": "111年特種考試地方政府公務人員考試", "original_question_number": 4, "answer_corrected": false, "flags": [], "civil_slug": "locality", "civil_category": "圖書資訊管理"}'::jsonb, NULL),
  ('locality-814ced5a-moex-00108', 'locality-814ced5a', 'locality-814ced5a-moex-111-01c5eaab', 'sub-locality-814ced5a-03', NULL, 'single_choice', '下列有關學習的成語，何者非認真努力之意？', '["孜孜矻矻", "九仞一簣", "目不窺園", "日旰忘食"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:35:28+00:00", "source_pdf_sha1": "e90a507a577f", "answer_pdf_sha1": "69eb6bd30069", "source_family": "moex-gov-tw", "moex": {"exam_code": "111190", "c": "506", "s": "0105", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "國文(包括公文格式用語)", "year": "111", "exam_name": "111年特種考試地方政府公務人員考試", "original_question_number": 5, "answer_corrected": false, "flags": [], "civil_slug": "locality", "civil_category": "圖書資訊管理"}'::jsonb, NULL),
  ('locality-814ced5a-moex-00109', 'locality-814ced5a', 'locality-814ced5a-moex-111-01c5eaab', 'sub-locality-814ced5a-03', NULL, 'single_choice', '下列語句「」中的用詞，何者最為妥切？', '["這隻大狗一路「拈花惹草」，非常有趣", "這位少女因智力不足常被欺負，「公道自在」", "張三為了等李四，「歷盡滄桑」在大門口守了一天", "這棟建築在重建的過程中被「肆意雕琢」，面目全非"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:35:28+00:00", "source_pdf_sha1": "e90a507a577f", "answer_pdf_sha1": "69eb6bd30069", "source_family": "moex-gov-tw", "moex": {"exam_code": "111190", "c": "506", "s": "0105", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "國文(包括公文格式用語)", "year": "111", "exam_name": "111年特種考試地方政府公務人員考試", "original_question_number": 6, "answer_corrected": false, "flags": [], "civil_slug": "locality", "civil_category": "圖書資訊管理"}'::jsonb, NULL),
  ('locality-814ced5a-moex-00110', 'locality-814ced5a', 'locality-814ced5a-moex-111-01c5eaab', 'sub-locality-814ced5a-03', NULL, 'single_choice', '下列選項中的成語運用，何者前後互換文意不變？', '["他忽然之間「福至心靈」，想到了一個好辦法／「肝膽相照」", "他的才華洋溢，在同學之中顯得「鶴立雞群」／「雷厲風行」", "我很想與他相會，可惜「緣慳一面」，始終無法如願／「秦晉之好」", "這兩個人「臭味相投」，很快就結為伙伴一起做壞事／「沆瀣一氣」"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:35:28+00:00", "source_pdf_sha1": "e90a507a577f", "answer_pdf_sha1": "69eb6bd30069", "source_family": "moex-gov-tw", "moex": {"exam_code": "111190", "c": "506", "s": "0105", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "國文(包括公文格式用語)", "year": "111", "exam_name": "111年特種考試地方政府公務人員考試", "original_question_number": 7, "answer_corrected": false, "flags": [], "civil_slug": "locality", "civil_category": "圖書資訊管理"}'::jsonb, NULL),
  ('locality-814ced5a-moex-00111', 'locality-814ced5a', 'locality-814ced5a-moex-111-01c5eaab', 'sub-locality-814ced5a-03', NULL, 'single_choice', '「生命中許多失敗，都是人們在放棄時，不知道他們離成功有多近。」依據這段話，成功的因素主要是：', '["自知之明", "行遠自邇", "捨近圖遠", "鍥而不捨"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:35:28+00:00", "source_pdf_sha1": "e90a507a577f", "answer_pdf_sha1": "69eb6bd30069", "source_family": "moex-gov-tw", "moex": {"exam_code": "111190", "c": "506", "s": "0105", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "國文(包括公文格式用語)", "year": "111", "exam_name": "111年特種考試地方政府公務人員考試", "original_question_number": 8, "answer_corrected": false, "flags": [], "civil_slug": "locality", "civil_category": "圖書資訊管理"}'::jsonb, NULL),
  ('locality-814ced5a-moex-00112', 'locality-814ced5a', 'locality-814ced5a-moex-111-01c5eaab', 'sub-locality-814ced5a-03', NULL, 'single_choice', '下列選項「」中的成語，何者運用最恰當？', '["王老師執教多年，作育英才無數，可謂「功著杏林」", "經常「動心忍性」亂發脾氣，頗容易引起無謂的糾紛", "仿冒歪風若不速加遏止，不法業者勢必「群起效尤」", "做事如不能按部就班，終必「雁行失序」，一敗塗地"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:35:28+00:00", "source_pdf_sha1": "e90a507a577f", "answer_pdf_sha1": "69eb6bd30069", "source_family": "moex-gov-tw", "moex": {"exam_code": "111190", "c": "506", "s": "0105", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "國文(包括公文格式用語)", "year": "111", "exam_name": "111年特種考試地方政府公務人員考試", "original_question_number": 9, "answer_corrected": false, "flags": [], "civil_slug": "locality", "civil_category": "圖書資訊管理"}'::jsonb, NULL),
  ('locality-814ced5a-moex-00113', 'locality-814ced5a', 'locality-814ced5a-moex-111-01c5eaab', 'sub-locality-814ced5a-03', NULL, 'single_choice', '「從遠古以來，傳統就像一條線，繫牢人類社會這一面大風箏，風箏飛得再怎麼高，線是不能斷的， 每一段線代表每個不同的時代，也代表著風箏的高度。當風箏斷了線，風箏就不會再有高度，只有隨 風遠去，而一直到墜地。」 關於文中「風箏與線」的比喻，說明最適當的是：', '["人類社會可藉由傳統的延續而提升文化高度", "人類社會維繫傳統的方法必須有一定的高度", "不同時代的傳統有各自的高度與維繫的方式", "傳統間的衝突若無法解決會導致社會的沉淪"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:35:28+00:00", "source_pdf_sha1": "e90a507a577f", "answer_pdf_sha1": "69eb6bd30069", "source_family": "moex-gov-tw", "moex": {"exam_code": "111190", "c": "506", "s": "0105", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "國文(包括公文格式用語)", "year": "111", "exam_name": "111年特種考試地方政府公務人員考試", "original_question_number": 10, "answer_corrected": false, "flags": [], "civil_slug": "locality", "civil_category": "圖書資訊管理"}'::jsonb, NULL),
  ('locality-814ced5a-moex-00114', 'locality-814ced5a', 'locality-814ced5a-moex-111-01c5eaab', 'sub-locality-814ced5a-03', NULL, 'single_choice', '「日本時期，總督府認定的神社，大多是原住民部落神社。這些神社的參拜者只限於管理原住民與部 落的警員，卻受到總督府的承認。照理說，這種神社並不能算是『讓公眾祭拜』，儘管如此，總督府 還是給予認定，原因是為了藉由理番政策當中的同化政策，培養更鞏固的敬神崇皇觀念，故神社的認 定有其必要。」 關於「神社」的敘述，最貼近上文旨意的選項是：', '["日本總督府廣設原住民部落神社，是為了讓更多民眾祭拜", "總督府從寬認定部落神社，是為了強化原住民的日本認同", "能夠讓總督府承認的神社，都是公眾可以自由參拜的場所", "總督府強化部落神社的功能，在教導原住民認識日本文化"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:35:28+00:00", "source_pdf_sha1": "e90a507a577f", "answer_pdf_sha1": "69eb6bd30069", "source_family": "moex-gov-tw", "moex": {"exam_code": "111190", "c": "506", "s": "0105", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "國文(包括公文格式用語)", "year": "111", "exam_name": "111年特種考試地方政府公務人員考試", "original_question_number": 11, "answer_corrected": false, "flags": [], "civil_slug": "locality", "civil_category": "圖書資訊管理"}'::jsonb, NULL),
  ('locality-814ced5a-moex-00115', 'locality-814ced5a', 'locality-814ced5a-moex-111-01c5eaab', 'sub-locality-814ced5a-03', NULL, 'single_choice', '「程普因為自己年紀長，好幾次仗著資歷，刻意讓周瑜難堪。周瑜不吭聲，臉色謙遜，始終沒和程普 計較。後來，程普自己對周瑜越來越敬佩，也與周瑜的關係更加親密，於是他跟別人說：『與周公瑾 交朋友，就像喝濃醇的美酒，不知不覺就醉了。』」 根據上文，下列選項關於周瑜（周公瑾）的為人，正確的是：', '["公私不分，以退為進", "廣結善緣，酒量過人", "大度能容，胸襟過人", "敬長愛幼，委屈求全"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:35:28+00:00", "source_pdf_sha1": "e90a507a577f", "answer_pdf_sha1": "69eb6bd30069", "source_family": "moex-gov-tw", "moex": {"exam_code": "111190", "c": "506", "s": "0105", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "國文(包括公文格式用語)", "year": "111", "exam_name": "111年特種考試地方政府公務人員考試", "original_question_number": 12, "answer_corrected": false, "flags": [], "civil_slug": "locality", "civil_category": "圖書資訊管理"}'::jsonb, NULL)
